class Scripts {
    String test;

    Scripts({
        required this.test,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        test: json["test"],
    );

    Map<String, dynamic> toJson() => {
        "test": test,
    };
}
